const apiResponse = $json;
const passStateData = $('Pass State').item.json;

const prevCompanies = passStateData.allCompanies || [];
const newCompanies = apiResponse.results || [];
const cursor = apiResponse.paging?.next?.after || null;

return {
  json: {
    after: cursor,
    allCompanies: [...prevCompanies, ...newCompanies]
  }
};

const allCompanies = $input.first().json.allCompanies || [];
const now = new Date();
const todayMidnight = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate()));
const MS_PER_DAY = 86400000;

if (allCompanies.length === 0) {
  return [{ json: { empty: true, message: 'No companies with renewal dates found' } }];
}

return allCompanies.map(company => {
  const renewalDateStr = company.properties?.contract___renewal_date;
  let renewalDate;
  if (/^\d+$/.test(renewalDateStr)) {
    renewalDate = new Date(Number(renewalDateStr));
  } else {
    renewalDate = new Date(renewalDateStr);
  }

  const diffMs = renewalDate.getTime() - todayMidnight.getTime();
  const days = Math.ceil(diffMs / MS_PER_DAY);
  const value = days < 0 ? 'Overdue' : String(days);

  return {
    json: {
      id: String(company.id),
      name: company.properties?.name || 'Unknown',
      renewalDate: renewalDateStr,
      daysUntilRenewal: days,
      value: value
    }
  };
});

const items = $input.all().map(i => i.json);

if (items.length === 1 && items[0].empty) {
  return [{ json: { skip: true, message: items[0].message } }];
}

const BATCH_SIZE = 100;
const batches = [];

for (let i = 0; i < items.length; i += BATCH_SIZE) {
  const chunk = items.slice(i, i + BATCH_SIZE);
  batches.push({
    json: {
      inputs: chunk.map(c => ({
        id: c.id,
        properties: { days_until_next_renewal: c.value }
      })),
      batchIndex: Math.floor(i / BATCH_SIZE),
      batchCount: chunk.length
    }
  });
}

return batches;
